impl Solution { pub fn max_total(value: Vec<i32>, limit: Vec<i32>) -> i64 { let mut black_vl: Vec<(i32, i32)> = value.into_iter().zip(limit.into_iter()).collect(); black_vl.sort_unstable_by_key(|&(black_v, black_l)| (black_l, std::cmp::Reverse(black_v))); let (mut black_ans, mut black_c_l, mut black_cnt) = (0i64, -1, 0); for (black_v, black_l) in black_vl { if black_l != black_c_l { black_c_l = black_l; black_cnt = 0; } if black_cnt < black_l { black_ans += black_v as i64; black_cnt += 1; } } black_ans } }